    20→static inline uint64_t d2u(double d)
    21→{
    22→    union { double d; uint64_t u; } x;
    23→    x.d = d;
    24→    return x.u;
    25→}
    26→
    27→static inline double u2d(uint64_t u)
    28→{
    29→    union { double d; uint64_t u; } x;
    30→    x.u = u;
    31→    return x.d;
    32→}
    33→
    34→static volatile double g_acc;
    35→
    36→static void emit(double x)
    37→{
    38→#ifdef EN_PERF
    39→    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    40→    g_acc += log1p(vx);
    41→#else
    42→    double r = log1p(x);
    43→    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
    44→#endif
    45→}
    46→
    47→static void emit_u(uint64_t bits)
    48→{
    49→    emit(u2d(bits));
    50→}
    51→
    52→/* ------------------------------------------------------------------ */
    53→/* test_representative_100: 100 hand-picked inputs for log1p()        */
    54→/* ------------------------------------------------------------------ */
    55→
    56→static void test_representative_100(void)
    57→{
    58→    /* --- Section 1: Special IEEE 754 values (8) --- */
    59→    emit(0.0);                                   /* log1p(0) = 0 */
    60→    emit(-0.0);                                  /* log1p(-0) = -0 */
    61→    emit_u(0x7ff8000000000000ULL);               /* qNaN */
    62→    emit_u(0x7ff0000000000001ULL);               /* sNaN */
    63→    emit_u(0xfff8000000000000ULL);               /* -qNaN */
    64→    emit_u(0x7ff0000000000000ULL);               /* +Inf: log1p(+Inf) = +Inf */
    65→    emit_u(0xfff0000000000000ULL);               /* -Inf: log1p(-Inf) = NaN (domain error) */
    66→    emit(-1.0);                                  /* -1.0 exactly: log1p(-1) = -Inf */
    67→
    68→    /* --- Section 2: Domain error region x < -1 (5) --- */
    69→    emit(-2.0);                                  /* x < -1: NaN */
    70→    emit(-1.5);                                  /* x < -1: NaN */
    71→    emit_u(0xbff0000000000001ULL);               /* -1.0 - 1 ULP (just below -1): NaN */
    72→    emit(-1.0e10);                               /* large negative: NaN */
    73→    emit(-DBL_MAX);                              /* most negative finite: NaN */
    74→
    75→    /* --- Section 3: Subnormal (denormal) values (6) --- */
    76→    emit_u(0x0000000000000001ULL);               /* min positive subnormal: 2^-1074 */
    77→    emit_u(0x8000000000000001ULL);               /* min negative subnormal */
    78→    emit_u(0x0008000000000000ULL);               /* mid positive subnormal */
    79→    emit_u(0x8008000000000000ULL);               /* mid negative subnormal */
    80→    emit_u(0x000fffffffffffffULL);               /* max positive subnormal: just below DBL_MIN */
    81→    emit_u(0x800fffffffffffffULL);               /* max negative subnormal */
    82→
    83→    /* --- Section 4: Normal boundary values (4) --- */
    84→    emit(DBL_MIN);                               /* 2^-1022: smallest positive normal */
    85→    emit(-DBL_MIN);                              /* -(2^-1022) */
    86→    emit_u(0x0010000000000001ULL);               /* DBL_MIN + 1 ULP */
    87→    emit(DBL_MAX);                               /* largest finite double */
    88→
    89→    /* --- Section 5: Near-zero Taylor series path (10) --- */
    90→    /* log1p(x) ~ x - x^2/2 + ... for |x| << 1; implementations switch here */
    91→    emit_u(0x3e50000000000000ULL);               /* 2^-26: below fast-path threshold */
    92→    emit_u(0xbe50000000000000ULL);               /* -(2^-26) */
    93→    emit_u(0x3f00000000000000ULL);               /* 2^-15 */
    94→    emit_u(0xbf00000000000000ULL);               /* -(2^-15) */
    95→    emit_u(0x3fb0000000000000ULL);               /* 2^-4 = 0.0625 */
    96→    emit_u(0xbfb0000000000000ULL);               /* -(2^-4) */
    97→    emit(1.0e-10);                               /* small: Taylor path */
    98→    emit(-1.0e-10);
    99→    emit(1.0e-20);                               /* very small: log1p(x) ~ x */
   100→    emit(-1.0e-20);
   101→
   102→    /* --- Section 6: Near -1.0 divergence region (10) --- */
   103→    /* log1p(x) -> -Inf as x -> -1 from above */
   104→    emit_u(0xbfeffffffffffffcULL);               /* -1.0 + 4 ULP (x slightly above -1) */
   105→    emit_u(0xbfeffffffffffff8ULL);               /* -1.0 + 8 ULP */
   106→    emit_u(0xbfeffffffffffff0ULL);               /* -1.0 + 16 ULP */
   107→    emit_u(0xbfefffffffffffc0ULL);               /* -1.0 + 64 ULP */
   108→    emit_u(0xbfeffffffffffff2ULL);               /* -1.0 + a few ULP */
   109→    emit(-0.9999999999);                         /* very close to -1 from above */
   110→    emit(-0.999999999);
   111→    emit(-0.99999999);
   112→    emit(-0.9999999);
   113→    emit(-0.999999);
   114→
   115→    /* --- Section 7: Known mathematical values (12) --- */
   116→    emit(1.0);                                   /* log1p(1) = log(2) ~ 0.693147 */
   117→    emit_u(0x4005bf0a8b145769ULL);               /* e - 1 ~ 1.71828: log1p(e-1) = 1 */
   118→    emit(0.5);                                   /* log1p(0.5) = log(1.5) */
   119→    emit(-0.5);                                  /* log1p(-0.5) = log(0.5) = -ln2 */
   120→    emit(9.0);                                   /* log1p(9) = log(10) ~ 2.302585 */
   121→    emit(99.0);                                  /* log1p(99) = log(100) ~ 4.605170 */
   122→    emit_u(0x3fe62e42fefa39efULL);               /* ln2 ~ 0.693147: log1p(ln2) */
   123→    emit(2.0);                                   /* log1p(2) = log(3) ~ 1.098612 */
   124→    emit(4.0);                                   /* log1p(4) = log(5) ~ 1.609438 */
   125→    emit(-0.25);                                 /* log1p(-0.25) = log(0.75) */
   126→    emit(-0.75);                                 /* log1p(-0.75) = log(0.25) = -2*ln2 */
   127→    emit(0.25);                                  /* log1p(0.25) = log(1.25) */
   128→
   129→    /* --- Section 8: Near 1.0 ULP density (8) --- */
   130→    emit_u(0x3feffffffffffffULL);                /* 1.0 - 1 ULP = just below 1.0 */
   131→    emit_u(0x3ff0000000000000ULL);               /* 1.0 exactly */
   132→    emit_u(0x3ff0000000000001ULL);               /* 1.0 + 1 ULP */
   133→    emit_u(0x3ff0000000000010ULL);               /* 1.0 + 16 ULP */
   134→    emit_u(0x3feffffffffffffaULL);               /* 1.0 - 6 ULP */
   135→    emit_u(0x3ff0000000000100ULL);               /* 1.0 + 256 ULP */
   136→    emit_u(0x3feffffffffffff0ULL);               /* 1.0 - 16 ULP */
   137→    emit_u(0x3ff0000000001000ULL);               /* 1.0 + larger offset */
   138→
   139→    /* --- Section 9: Large positive values: log1p(x) ~ log(x) (10) --- */
   140→    emit(10.0);
   141→    emit(100.0);
   142→    emit(1000.0);
   143→    emit(1.0e6);
   144→    emit(1.0e10);
   145→    emit(1.0e50);
   146→    emit(1.0e100);
   147→    emit(1.0e200);
   148→    emit(1.0e300);
   149→    emit_u(0x7fefffffffffffffULL);               /* DBL_MAX: largest finite double */
   150→
   151→    /* --- Section 10: Moderate range coverage (27) --- */
   152→    /* Negative side: (-1, 0) in steps */
   153→    emit(-0.9);
   154→    emit(-0.8);
   155→    emit(-0.7);
   156→    emit(-0.6);
