   185→#ifndef EN_PERF
   186→/* 7. Sweep [-0.95, 100.0] in 200 steps */
   187→static void test_sweep(void)
   188→{
   189→    double lo = -0.95;
   190→    double hi = 100.0;
   191→    int nsteps = 200;
   192→    double step = (hi - lo) / (double)nsteps;
   193→
   194→    /* [-0.95, 100.0] */
   195→    for (int i = 0; i <= nsteps; i++)
   196→        emit(lo + (double)i * step);
   197→
   198→    /* [100.0, -0.95] (decreasing) */
   199→    for (int i = 0; i <= nsteps; i++)
   200→        emit(hi - (double)i * step);
   201→}
   202→
   203→/* 8. Sample [0, 0.1] with representative bit patterns */
   204→static void test_exhaustive_small(void)
   205→{
   206→    static const uint64_t vals[] = {
   207→        0x0000000000000000ULL, /* 0.0 */
   208→        0x3f847ae147ae147bULL, /* 0.01 */
   209→        0x3f9eb851eb851eb8ULL, /* 0.03 */
   210→        0x3fa999999999999aULL, /* 0.05 */
   211→        0x3fb4cccccccccccdULL, /* 0.08 */
   212→        0x3fb999999999999aULL, /* ~0.1 */
   213→    };
   214→    for (int i = 0; i < (int)(sizeof(vals)/sizeof(vals[0])); i++)
   215→        emit_u(vals[i]);
   216→}
   217→#endif
